function useCountdown(initial: number) {
  const [time, setTime] = useState(initial);
  const [running, setRunning] = useState(false);

  useEffect(() => {
    if (!running || time <= 0) return;
    const id = setInterval(() => setTime(t => t - 1), 1000);
    return () => clearInterval(id);
  }, [running, time]);

  const start = useCallback(() => setRunning(true), []);
  const reset = useCallback(() => {
    setRunning(false); setTime(initial);
  }, [initial]);

  return { time, running, start, reset };
}`}],o2=()=>{const[n,r]=S.useState(0),[s,o]=S.useState([]),[l,c]=S.useState("idle"),d=S.useRef(null),h=S.useRef(0),p=bp[n%bp.length],m=()=>++h.current;return S.useEffect(()=>{const g=p.question,x=p.code.split(`
